{
  // OpenCode runtime config. Docs: https://opencode.ai/docs/
  "$schema": "https://opencode.ai/config.json",
  "theme": "system",
  // The default agent is `kortix` — a generic general-knowledge worker.
  // Edit `.kortix/opencode/agents/kortix.md` (or add more agents in that folder).
  "default_agent": "kortix",
  // Kortix sessions are already sandboxed (isolated VM, ephemeral branch),
  // so the agent has full access by default. Tighten per-tool here if you
  // want a stricter policy. Docs: https://opencode.ai/docs/permissions/
  "permission": "allow",
  // Local plugins. Tools in `tools/` and plugins in `plugins/` are auto-discovered;
  // this array loads additional plugins by path. The PTY plugin adds pty_spawn /
  // pty_write / pty_read / pty_list / pty_kill for long-running & interactive shells.
  "plugin": ["./pty/pty-tools.ts"]
}

{
  "name": "kortix-opencode-config",
  "private": true,
  "//": "Dependencies for the custom tools in tools/. OpenCode runs `bun install` here at startup so tools can import them. The sandbox image pre-warms Bun's cache with these so the boot-time install is offline and fast.",
  "dependencies": {
    "@mendable/firecrawl-js": "^4.25.1",
    "@tavily/core": "^0.7.3",
    "replicate": "^1.4.0"
  }
}

/**
 * kortix-simple-memory — opencode plugin
 *
 * Injects `.kortix/memory/MEMORY.md` (the project-brain index) into the
 * front of the system prompt as a `<kortix-memory>` block on every LLM
 * call. Sub-files in `.kortix/memory/` are NOT auto-loaded — the agent
 * reads them on demand with the built-in `read` tool.
 *
 * Why front of `output.system[]`: it sits in the cached prefix of the
 * prompt, so as long as MEMORY.md doesn't change mid-session the
 * provider's prefix cache keeps hitting.
 *
 * For the rubric on what belongs in project memory and how to update
 * it, load the `kortix-memory` skill.
 */

import type { Plugin } from "@opencode-ai/plugin";
import { readFile, readdir, stat } from "node:fs/promises";
import { join } from "node:path";

type Options = {
  /** Path relative to project root. Default: ".kortix/memory" */
  dir?: string;
  /** Index filename inside `dir`. Default: "MEMORY.md" */
  index?: string;
  /** Soft cap on the injected block to keep the prompt cache tight. */
  maxChars?: number;
};

export const KortixSimpleMemory: Plugin = async (ctx, opts: Options = {}) => {
  const memDir   = opts.dir   ?? ".kortix/memory";
  const indexRel = opts.index ?? "MEMORY.md";
  const maxChars = opts.maxChars ?? 8192;

  async function readBlock(): Promise<string | null> {
    const root = ctx.directory;
    const indexPath = join(root, memDir, indexRel);

    let body: string;
    try {
      body = await readFile(indexPath, "utf8");
    } catch {
      return null; // memory not initialized — no-op
    }

    // List sibling files so the agent knows what's available to `read`.
    let listing: string[] = [];
    try {
      const entries = await readdir(join(root, memDir));
      for (const name of entries) {
        if (name === indexRel || name.startsWith(".")) continue;
        const full = join(root, memDir, name);
        const s = await stat(full);
        if (s.isFile()) listing.push(name);
      }
      listing.sort();
    } catch { /* empty dir is fine */ }

    const filesLine = listing.length
      ? `Files in ${memDir}/ available via \`read\` / \`bash\`: ${listing.join(", ")}`
      : "";

    let block =
      `<kortix-memory source="${memDir}/${indexRel}">\n` +
      `[Project brain — durable, team-shared knowledge about this project.\n` +
      ` The index below names sub-files in ${memDir}/. Open them with \`read\`\n` +
      ` only when the index points at one that's relevant to the current task.\n` +
      ` Load the \`kortix-memory\` skill when adding or updating memory.]\n\n` +
      body.trim() +
      (filesLine ? `\n\n${filesLine}` : "") +
      `\n</kortix-memory>`;

    if (block.length > maxChars) {
      block = block.slice(0, maxChars - 32) + "\n[...truncated]\n</kortix-memory>";
    }
    return block;
  }

  return {
    "experimental.chat.system.transform": async (_input, output) => {
      const block = await readBlock();
      if (!block) return;
      output.system.unshift(block);
    },
  };
};

export default KortixSimpleMemory;

import type { PluginContext, PluginResult } from './plugin/types.ts'
import { initManager, isBunPtyAvailable, bunPtyLoadError, manager } from './plugin/pty/manager.ts'
import { initPermissions } from './plugin/pty/permissions.ts'
import { ptySpawn } from './plugin/pty/tools/spawn.ts'
import { ptyWrite } from './plugin/pty/tools/write.ts'
import { ptyRead } from './plugin/pty/tools/read.ts'
import { ptyList } from './plugin/pty/tools/list.ts'
import { ptyKill } from './plugin/pty/tools/kill.ts'

export const PTYPlugin = async ({ client, directory, serverUrl }: PluginContext): Promise<PluginResult> => {
  // ── Load-time diagnostics ───────────────────────────────────────────────
  const available = isBunPtyAvailable()
  if (!available) {
    const loadErr = bunPtyLoadError()
    console.error(
      `[opencode-pty] ⚠ Plugin loaded but the PTY backend is NOT available.\n` +
        `  PTY tools (pty_spawn, pty_read, pty_write, pty_list, pty_kill) will return errors.\n` +
        `  Load error: ${loadErr}\n` +
        `  Platform: ${process.platform}/${process.arch}\n` +
        `  Runtime: ${typeof Bun !== 'undefined' ? `Bun ${(Bun as any).version}` : 'NOT Bun'}\n` +
        `  cwd: ${process.cwd()}\n` +
        `  directory: ${directory}\n` +
        `  Troubleshooting:\n` +
        `    1. Is the OpenCode /pty backend responding?\n` +
        `    2. Is OpenCode serving on ${serverUrl.origin}?\n` +
        `    3. Are PTY websocket connections allowed in this runtime?\n`
    )
  } else {
    console.log(
      `[opencode-pty] ✓ Plugin loaded. PTY backend available. Platform: ${process.platform}/${process.arch}`
    )
  }

  initPermissions(client, directory)
  initManager(client, serverUrl, directory)

  return {
    tool: {
      pty_spawn: ptySpawn,
      pty_write: ptyWrite,
      pty_read: ptyRead,
      pty_list: ptyList,
      pty_kill: ptyKill,
    },
    event: async ({ event }) => {
      if (event.type === 'session.deleted') {
        manager.cleanupBySession(event.properties.info.id)
      }
    },
  }
}

export default PTYPlugin

// Shared constants for the PTY plugin

// PTY terminal and UI constants
export const DEFAULT_TERMINAL_COLS = 120
export const DEFAULT_TERMINAL_ROWS = 40
export const NOTIFICATION_LINE_TRUNCATE = 250
export const NOTIFICATION_TITLE_TRUNCATE = 64

// Default buffer size in characters (approximately 1MB)
const DEFAULT_MAX_BUFFER_SIZE = parseInt(process.env.PTY_MAX_BUFFER_SIZE || '1000000', 10)

export interface SearchMatch {
  lineNumber: number
  text: string
}

export class RingBuffer {
  private buffer: string = ''
  private maxSize: number

  constructor(maxSize: number = DEFAULT_MAX_BUFFER_SIZE) {
    this.maxSize = maxSize
  }

  append(data: string): void {
    this.buffer += data
    if (this.buffer.length > this.maxSize) {
      this.buffer = this.buffer.slice(-this.maxSize)
    }
  }

  private splitBufferLines(): string[] {
    const lines: string[] = this.buffer.split('\n')
    // Remove empty string at end if buffer doesn't end with newline
    if (lines.length && lines[lines.length - 1] === '') {
      lines.pop()
    }
    return lines
  }

  read(offset: number = 0, limit?: number): string[] {
    if (this.buffer === '') return []
    const lines: string[] = this.splitBufferLines()
    const start = Math.max(0, offset)
    const end = limit !== undefined ? start + limit : lines.length
    return lines.slice(start, end)
  }

  readRaw(): string {
    return this.buffer
  }

  search(pattern: RegExp): SearchMatch[] {
    const matches: SearchMatch[] = []
    const lines: string[] = this.splitBufferLines()

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i]
      if (line && pattern.test(line)) {
        matches.push({ lineNumber: i + 1, text: line })
      }
    }
    return matches
  }

  get length(): number {
    if (this.buffer === '') return 0
    const lines = this.splitBufferLines()
    return lines.length
  }

  get byteLength(): number {
    return this.buffer.length
  }

  flush(): void {
    // No-op in new implementation
  }

  clear(): void {
    this.buffer = ''
  }
}

import type { PTYSessionInfo } from './types.ts'

export function formatSessionInfo(session: PTYSessionInfo): string[] {
  const exitInfo = session.exitCode !== undefined ? ` | exit: ${session.exitCode}` : ''
  const exitSignal = session.exitSignal ? ` | signal: ${session.exitSignal}` : ''
  return [
    `[${session.id}] ${session.title}`,
    `  Command: ${session.command} ${session.args.join(' ')}`,
    `  Status: ${session.status}${exitInfo}${exitSignal}`,
    `  PID: ${session.pid}`,
    `  Lines: ${session.lineCount}`,
    `  Workdir: ${session.workdir}`,
    `  Created: ${session.createdAt}`,
    '',
  ]
}

export function formatLine(line: string, lineNum: number, maxLength: number = 2000): string {
  const lineNumStr = lineNum.toString().padStart(5, '0')
  const truncatedLine = line.length > maxLength ? `${line.slice(0, maxLength)}...` : line
  return `${lineNumStr}| ${truncatedLine}`
}

import type { OpencodeClient } from '@opencode-ai/sdk'
import { RingBuffer } from './buffer.ts'
import { SessionLifecycleManager } from './session-lifecycle.ts'
import type { PTYSession, PTYSessionInfo, ReadResult, SearchResult, SpawnOptions } from './types.ts'

type BuiltinPtyInfo = {
  id: string
  title: string
  command: string
  args: string[]
  cwd: string
  status: 'running' | 'exited'
  pid: number
}

type SessionUpdateCallback = (session: PTYSessionInfo) => void
type RawOutputCallback = (session: PTYSessionInfo, rawData: string) => void

export const sessionUpdateCallbacks: SessionUpdateCallback[] = []
export const rawOutputCallbacks: RawOutputCallback[] = []

export function registerSessionUpdateCallback(callback: SessionUpdateCallback) {
  sessionUpdateCallbacks.push(callback)
}

export function removeSessionUpdateCallback(callback: SessionUpdateCallback) {
  const index = sessionUpdateCallbacks.indexOf(callback)
  if (index !== -1) sessionUpdateCallbacks.splice(index, 1)
}

export function registerRawOutputCallback(callback: RawOutputCallback): void {
  rawOutputCallbacks.push(callback)
}

export function removeRawOutputCallback(callback: RawOutputCallback): void {
  const index = rawOutputCallbacks.indexOf(callback)
  if (index !== -1) rawOutputCallbacks.splice(index, 1)
}

function notifySessionUpdate(session: PTYSessionInfo) {
  for (const callback of sessionUpdateCallbacks) {
    try {
      callback(session)
    } catch {}
  }
}

function notifyRawOutput(session: PTYSessionInfo, rawData: string): void {
  for (const callback of rawOutputCallbacks) {
    try {
      callback(session, rawData)
    } catch {}
  }
}

let _client: OpencodeClient | null = null
let _directory = process.cwd()
let _httpBase = 'http://127.0.0.1:4096'
let _wsBase = 'ws://127.0.0.1:4096'
let _backendAvailable = true
let _backendLoadError: string | null = null

function normalizeBase(input: URL | string | undefined, protocol: 'http' | 'ws'): string {
  const url = typeof input === 'string' ? new URL(input) : new URL(input?.toString() ?? 'http://127.0.0.1:4096')
  if (url.hostname === '0.0.0.0') url.hostname = '127.0.0.1'
  url.protocol = protocol === 'ws'
    ? (url.protocol === 'https:' ? 'wss:' : 'ws:')
    : (url.protocol === 'wss:' ? 'https:' : 'http:')
  url.pathname = ''
  url.search = ''
  url.hash = ''
  return url.toString().replace(/\/$/, '')
}

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${_httpBase}${path}`, init)
  if (!res.ok) {
    const body = await res.text().catch(() => '')
    throw new Error(`PTY backend ${init?.method ?? 'GET'} ${path} failed: ${res.status} ${body}`)
  }
  return (await res.json()) as T
}

function escapeXml(text: string): string {
  return text
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
}

class PTYManager {
  private sessions = new Map<string, PTYSession>()
  private localSessions = new SessionLifecycleManager()

  init(client: OpencodeClient, serverUrl?: URL, directory?: string): void {
    _client = client
    if (directory) _directory = directory
    _httpBase = normalizeBase(serverUrl, 'http')
    _wsBase = normalizeBase(serverUrl, 'ws')
    _backendAvailable = true
    _backendLoadError = null
  }

  async probe(): Promise<void> {
    try {
      await request<BuiltinPtyInfo[]>('/pty')
      _backendAvailable = true
      _backendLoadError = null
    } catch (err) {
      _backendAvailable = false
      _backendLoadError = err instanceof Error ? err.message : String(err)
    }
  }

  clearAllSessions(): void {
    for (const session of this.sessions.values()) {
      try {
        session.process?.kill?.()
      } catch {}
    }
    this.sessions.clear()
    this.localSessions.clearAllSessions()
  }

  private toInfo(session: PTYSession): PTYSessionInfo {
    return {
      id: session.id,
      title: session.title,
      description: session.description,
      command: session.command,
      args: session.args,
      workdir: session.workdir,
      status: session.status,
      exitCode: session.exitCode,
      exitSignal: session.exitSignal,
      pid: session.pid,
      createdAt: session.createdAt,
      lineCount: session.buffer.length,
    }
  }

  private async sendExitNotification(session: PTYSession): Promise<void> {
    if (!_client || !session.notifyOnExit) return
    const lines = [
      '<pty_exited>',
      `ID: ${session.id}`,
      `Title: ${session.title}`,
      `Exit code: ${session.exitCode ?? 'unknown'}`,
      `Output lines: ${session.buffer.length}`,
      '</pty_exited>',
    ]
    try {
      await _client.session.prompt({
        path: { id: session.parentSessionId },
        body: { noReply: true, parts: [{ type: 'text', text: lines.join('\n') }] },
      })
    } catch {}
  }

  private connectSocket(session: PTYSession): Promise<void> {
    return new Promise((resolve, reject) => {
      const ws = new WebSocket(`${_wsBase}/pty/${session.id}/connect`)
      let settled = false
      const settle = (fn: () => void) => {
        if (settled) return
        settled = true
        fn()
      }

      ws.onopen = () => {
        session.process = {
          pid: session.pid,
          onData: () => {},
          onExit: () => {},
          write: (data: string) => ws.send(data),
          kill: () => ws.close(),
        }
        settle(resolve)
      }

      ws.onmessage = (event) => {
        const text = typeof event.data === 'string' ? event.data : ''
        if (!text) return
        session.buffer.append(text)
        notifyRawOutput(this.toInfo(session), text)
        notifySessionUpdate(this.toInfo(session))
      }

      ws.onclose = async () => {
        session.status = session.status === 'killing' ? 'killed' : 'exited'
        notifySessionUpdate(this.toInfo(session))
        await this.sendExitNotification(session)
      }

      ws.onerror = () => {
        settle(() => reject(new Error(`PTY websocket connection failed for ${session.id}`)))
      }
    })
  }

  async spawn(opts: SpawnOptions): Promise<PTYSessionInfo> {
    if (!_backendAvailable) {
      await this.probe()
    }

    if (!_backendAvailable) {
      const info = await this.localSessions.spawn(
        opts,
        (session, rawData) => {
          notifyRawOutput(this.localSessions.toInfo(session), rawData)
          notifySessionUpdate(this.localSessions.toInfo(session))
        },
        async (session) => {
          notifySessionUpdate(this.localSessions.toInfo(session))
          await this.sendExitNotification(session)
        },
      )
      notifySessionUpdate(info)
      return info
    }

    const cwd = opts.workdir ?? _directory
    const created = await request<BuiltinPtyInfo>('/pty', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        command: opts.command,
        args: opts.args ?? [],
        cwd,
        title: opts.title,
        env: opts.env,
      }),
    })

    const session: PTYSession = {
      id: created.id,
      title: created.title,
      description: opts.description,
      command: created.command,
      args: created.args,
      workdir: created.cwd,
      env: opts.env,
      status: created.status,
      pid: created.pid,
      createdAt: new Date().toISOString(),
      parentSessionId: opts.parentSessionId,
      parentAgent: opts.parentAgent,
      notifyOnExit: opts.notifyOnExit ?? false,
      buffer: new RingBuffer(),
      process: null,
    }

    this.sessions.set(session.id, session)
    try {
      await this.connectSocket(session)
    } catch (err) {
      this.sessions.delete(session.id)
      await request(`/pty/${session.id}`, { method: 'DELETE' }).catch(() => undefined)
      throw err
    }

    notifySessionUpdate(this.toInfo(session))
    return this.toInfo(session)
  }

  async write(id: string, data: string): Promise<boolean> {
    const localSession = this.localSessions.getSession(id)
    if (localSession?.process) {
      localSession.process.write(data)
      return true
    }

    const session = this.sessions.get(id)
    if (!session || !session.process) return false
    session.process.write(data)
    return true
  }

  read(id: string, offset: number = 0, limit?: number): ReadResult | null {
    const localSession = this.localSessions.getSession(id)
    if (localSession) {
      const lines = localSession.buffer.read(offset, limit)
      const totalLines = localSession.buffer.length
      return {
        lines,
        totalLines,
        offset,
        hasMore: offset + lines.length < totalLines,
      }
    }

    const session = this.sessions.get(id)
    if (!session) return null
    const lines = session.buffer.read(offset, limit)
    const totalLines = session.buffer.length
    return {
      lines,
      totalLines,
      offset,
      hasMore: offset + lines.length < totalLines,
    }
  }

  search(id: string, pattern: RegExp, offset: number = 0, limit?: number): SearchResult | null {
    const localSession = this.localSessions.getSession(id)
    if (localSession) {
      const matches = localSession.buffer.search(pattern)
      const paged = limit !== undefined ? matches.slice(offset, offset + limit) : matches.slice(offset)
      return {
        matches: paged,
        totalMatches: matches.length,
        totalLines: localSession.buffer.length,
        offset,
        hasMore: offset + paged.length < matches.length,
      }
    }

    const session = this.sessions.get(id)
    if (!session) return null
    const matches = session.buffer.search(pattern)
    const paged = limit !== undefined ? matches.slice(offset, offset + limit) : matches.slice(offset)
    return {
      matches: paged,
      totalMatches: matches.length,
      totalLines: session.buffer.length,
      offset,
      hasMore: offset + paged.length < matches.length,
    }
  }

  async list(): Promise<PTYSessionInfo[]> {
    try {
      if (_backendAvailable) {
        const live = await request<BuiltinPtyInfo[]>('/pty')
        const liveIds = new Set(live.map((item) => item.id))
        for (const item of live) {
          const existing = this.sessions.get(item.id)
          if (existing) {
            existing.title = item.title
            existing.command = item.command
            existing.args = item.args
            existing.workdir = item.cwd
            existing.status = item.status
            existing.pid = item.pid
          } else {
            this.sessions.set(item.id, {
              id: item.id,
              title: item.title,
              command: item.command,
              args: item.args,
              workdir: item.cwd,
              status: item.status,
              pid: item.pid,
              createdAt: new Date().toISOString(),
              parentSessionId: '',
              notifyOnExit: false,
              buffer: new RingBuffer(),
              process: null,
            })
          }
        }
        for (const [id, session] of this.sessions) {
          if (!liveIds.has(id) && session.status === 'running') session.status = 'exited'
        }
      }
    } catch {}
    return [
      ...Array.from(this.sessions.values()).map((session) => this.toInfo(session)),
      ...this.localSessions.listSessions().map((session) => this.localSessions.toInfo(session)),
    ]
  }

  get(id: string): PTYSessionInfo | null {
    const localSession = this.localSessions.getSession(id)
    if (localSession) return this.localSessions.toInfo(localSession)

    const session = this.sessions.get(id)
    return session ? this.toInfo(session) : null
  }

  async kill(id: string, cleanup: boolean = false): Promise<boolean> {
    if (this.localSessions.getSession(id)) {
      return this.localSessions.kill(id, cleanup)
    }

    const session = this.sessions.get(id)
    if (!session) return false
    session.status = 'killing'
    try {
      await request(`/pty/${id}`, { method: 'DELETE' })
    } catch {
      return false
    }
    session.status = 'killed'
    try {
      session.process?.kill?.()
    } catch {}
    if (cleanup) {
      session.buffer.clear()
      this.sessions.delete(id)
    }
    notifySessionUpdate(this.toInfo(session))
    return true
  }

  cleanupBySession(parentSessionId: string): void {
    this.localSessions.cleanupBySession(parentSessionId)
    for (const [id, session] of this.sessions) {
      if (session.parentSessionId === parentSessionId) {
        this.kill(id, true).catch(() => undefined)
      }
    }
  }
}

export const manager = new PTYManager()

export function isBunPtyAvailable(): boolean {
  return _backendAvailable
}

export function bunPtyLoadError(): string | null {
  return _backendLoadError
}

export function initManager(opcClient: OpencodeClient, serverUrl?: URL, directory?: string): void {
  manager.init(opcClient, serverUrl, directory)
  manager.probe().catch(() => undefined)
}

export async function ensurePtyBackendAvailable(): Promise<void> {
  if (_backendAvailable) return
  await manager.probe()
}

export function wrapPtyText(text: string): string {
  return escapeXml(text)
}

import type { PTYSession } from './types.ts'
import type { OpencodeClient } from '@opencode-ai/sdk'
import { NOTIFICATION_LINE_TRUNCATE, NOTIFICATION_TITLE_TRUNCATE } from '../constants.ts'

export class NotificationManager {
  private client: OpencodeClient | null = null

  init(client: OpencodeClient): void {
    this.client = client
  }

  async sendExitNotification(session: PTYSession, exitCode: number): Promise<void> {
    if (!this.client) {
      return
    }

    try {
      const message = this.buildExitNotification(session, exitCode)
      await this.client.session.promptAsync({
        path: { id: session.parentSessionId },
        body: {
          parts: [{ type: 'text', text: message }],
          ...(session.parentAgent ? { agent: session.parentAgent } : {}),
        },
      })
    } catch {
      // Ignore notification errors
    }
  }

  private buildExitNotification(session: PTYSession, exitCode: number): string {
    const lineCount = session.buffer.length
    let lastLine = ''
    if (lineCount > 0) {
      for (let i = lineCount - 1; i >= 0; i--) {
        const bufferLines = session.buffer.read(i, 1)
        const line = bufferLines[0]
        if (line !== undefined && line.trim() !== '') {
          lastLine =
            line.length > NOTIFICATION_LINE_TRUNCATE
              ? `${line.slice(0, NOTIFICATION_LINE_TRUNCATE)}...`
              : line
          break
        }
      }
    }

    const displayTitle = session.description ?? session.title
    const truncatedTitle =
      displayTitle.length > NOTIFICATION_TITLE_TRUNCATE
        ? `${displayTitle.slice(0, NOTIFICATION_TITLE_TRUNCATE)}...`
        : displayTitle

    const hint = exitCode === 0
      ? 'Use pty_read to check the full output.'
      : 'Process failed. Use pty_read with the pattern parameter to search for errors in the output.'

    const lines = [
      '<pty_exited>',
      `ID: ${session.id}`,
      `Description: ${truncatedTitle}`,
      `Exit Code: ${exitCode}`,
      `Output Lines: ${lineCount}`,
      `Last Line: ${lastLine}`,
      `Hint: ${hint}`,
      '</pty_exited>',
    ]

    return lines.join('\n')
  }
}

import type { PTYSession, ReadResult, SearchResult } from './types.ts'

export class OutputManager {
  write(session: PTYSession, data: string): boolean {
    try {
      session.process?.write(data)
      return true
    } catch {
      return true // allow write to exited process for tests
    }
  }

  read(session: PTYSession, offset: number = 0, limit?: number): ReadResult {
    const lines = session.buffer.read(offset, limit)
    const totalLines = session.buffer.length
    const hasMore = offset + lines.length < totalLines
    return { lines, totalLines, offset, hasMore }
  }

  search(session: PTYSession, pattern: RegExp, offset: number = 0, limit?: number): SearchResult {
    const allMatches = session.buffer.search(pattern)
    const totalMatches = allMatches.length
    const totalLines = session.buffer.length
    const paginatedMatches =
      limit !== undefined ? allMatches.slice(offset, offset + limit) : allMatches.slice(offset)
    const hasMore = offset + paginatedMatches.length < totalMatches
    return { matches: paginatedMatches, totalMatches, totalLines, offset, hasMore }
  }
}

import type { PluginClient } from '../types.ts'
import { allStructured } from './wildcard.ts'

type PermissionAction = 'allow' | 'ask' | 'deny'
type BashPermissions = PermissionAction | Record<string, PermissionAction>

interface PermissionConfig {
  bash?: BashPermissions
  external_directory?: PermissionAction
}

let _client: PluginClient | null = null
let _directory: string | null = null

export function initPermissions(client: PluginClient, directory: string): void {
  _client = client
  _directory = directory
}

async function getPermissionConfig(): Promise<PermissionConfig> {
  if (!_client) {
    return {}
  }
  try {
    const response = await _client.config.get()
    if (response.error || !response.data) {
      return {}
    }
    return (response.data as { permission?: PermissionConfig }).permission ?? {}
  } catch {
    return {}
  }
}

async function showToast(
  message: string,
  variant: 'info' | 'success' | 'error' = 'info'
): Promise<void> {
  if (!_client) return
  try {
    await _client.tui.showToast({ body: { message, variant } })
  } catch {
    // Ignore toast errors
  }
}

async function denyWithToast(msg: string, details?: string): Promise<never> {
  await showToast(msg, 'error')
  throw new Error(details ? `${msg} ${details}` : msg)
}

async function handleAskPermission(commandLine: string): Promise<never> {
  await denyWithToast(
    `PTY: Command "${commandLine}" requires permission (treated as denied)`,
    `PTY spawn denied: Command "${commandLine}" requires user permission which is not supported by this plugin. Configure explicit "allow" or "deny" in your opencode.json permission.bash settings.`
  )
  throw new Error('Unreachable') // For TS, should never hit.
}

export async function checkCommandPermission(command: string, args: string[]): Promise<void> {
  const config = await getPermissionConfig()
  const bashPerms = config.bash

  if (!bashPerms) {
    return
  }

  if (typeof bashPerms === 'string') {
    if (bashPerms === 'deny') {
      await denyWithToast('PTY spawn denied: All bash commands are disabled by user configuration.')
    }
    if (bashPerms === 'ask') {
      await handleAskPermission(command)
    }
    return
  }

  const action = allStructured({ head: command, tail: args }, bashPerms)

  if (action === 'deny') {
    await denyWithToast(
      `PTY spawn denied: Command "${command} ${args.join(' ')}" is explicitly denied by user configuration.`
    )
  }

  if (action === 'ask') {
    await handleAskPermission(`${command} ${args.join(' ')}`)
  }
}

export async function checkWorkdirPermission(workdir: string): Promise<void> {
  if (!_directory) {
    return
  }

  const normalizedWorkdir = workdir.replace(/\/$/, '')
  const normalizedProject = _directory.replace(/\/$/, '')

  if (normalizedWorkdir.startsWith(normalizedProject)) {
    return
  }

  const config = await getPermissionConfig()
  const extDirPerm = config.external_directory

  if (extDirPerm === 'deny') {
    await denyWithToast(
      `PTY spawn denied: Working directory "${workdir}" is outside project directory "${_directory}". External directory access is denied by user configuration.`
    )
  }

  if (extDirPerm === 'ask') {
    // TODO: Implement user prompt for external directory access
  }
}

import { RingBuffer } from './buffer.ts'
import type { PTYSession, PTYSessionInfo, SpawnOptions } from './types.ts'
import { DEFAULT_TERMINAL_COLS, DEFAULT_TERMINAL_ROWS } from '../constants.ts'
import { existsSync } from 'node:fs'

// ── Lazy bun-pty import ─────────────────────────────────────────────────────
// bun-pty is a Bun-native module. Static imports crash the whole module graph
// if the native addon isn't available. We lazy-load at first spawn instead.
let _bunPtySpawn: ((...args: any[]) => any) | null = null
let _bunPtyLoadAttempted = false
let _bunPtyError: string | null = null

async function getBunPtySpawn(): Promise<(...args: any[]) => any> {
  if (_bunPtySpawn) return _bunPtySpawn

  if (_bunPtyLoadAttempted) {
    throw new Error(
      `[PTY spawn] bun-pty previously failed to load: ${_bunPtyError}. ` +
        `Cannot spawn PTY sessions. Fix the underlying issue and restart.`
    )
  }

  _bunPtyLoadAttempted = true
  try {
    const mod = await import('bun-pty') as any
    _bunPtySpawn = mod.spawn ?? mod.default?.spawn
    if (!_bunPtySpawn) {
      throw new Error(`bun-pty module loaded but 'spawn' export not found. Exports: ${Object.keys(mod).join(', ')}`)
    }
    return _bunPtySpawn
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err)
    _bunPtyError = msg
    throw new Error(
      `[PTY spawn] Failed to load bun-pty native module.\n` +
        `  Error: ${msg}\n` +
        `  Platform: ${process.platform}/${process.arch}\n` +
        `  Runtime: ${typeof Bun !== 'undefined' ? `Bun ${(Bun as any).version}` : 'NOT Bun (bun-pty requires Bun!)'}\n` +
        `  Fix: cd plugin/opencode-pty && bun install`
    )
  }
}

// ── Session lifecycle ───────────────────────────────────────────────────────
const SESSION_ID_BYTE_LENGTH = 4

function generateId(): string {
  const hex = Array.from(crypto.getRandomValues(new Uint8Array(SESSION_ID_BYTE_LENGTH)))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
  return `pty_${hex}`
}

export class SessionLifecycleManager {
  private sessions: Map<string, PTYSession> = new Map()

  private createSessionObject(opts: SpawnOptions): PTYSession {
    const id = generateId()
    const args = opts.args ?? []
    const workdir = opts.workdir ?? process.cwd()
    const title =
      opts.title ?? (`${opts.command} ${args.join(' ')}`.trim() || `Terminal ${id.slice(-4)}`)

    const buffer = new RingBuffer()
    return {
      id,
      title,
      description: opts.description,
      command: opts.command,
      args,
      workdir,
      env: opts.env,
      status: 'running',
      pid: 0, // will be set after spawn
      createdAt: new Date().toISOString(),
      parentSessionId: opts.parentSessionId,
      parentAgent: opts.parentAgent,
      notifyOnExit: opts.notifyOnExit ?? false,
      buffer,
      process: null, // will be set
    }
  }

  private async spawnProcess(session: PTYSession): Promise<void> {
    // Pre-flight checks with actionable diagnostics
    if (!session.command) {
      throw new Error(`[PTY spawn] command is empty/undefined. Provide a valid command.`)
    }

    if (session.workdir && !existsSync(session.workdir)) {
      throw new Error(
        `[PTY spawn] workdir does not exist: "${session.workdir}". ` +
          `Create the directory first or omit workdir to use cwd.`
      )
    }

    const env = { ...process.env, ...session.env } as Record<string, string>
    const spawnContext = {
      command: session.command,
      args: session.args,
      workdir: session.workdir,
      envKeys: session.env ? Object.keys(session.env) : [],
      cols: DEFAULT_TERMINAL_COLS,
      rows: DEFAULT_TERMINAL_ROWS,
    }

    // Lazy-load bun-pty spawn
    const bunPtySpawn = await getBunPtySpawn()

    try {
      const ptyProcess = bunPtySpawn(session.command, session.args, {
        name: 'xterm-256color',
        cols: DEFAULT_TERMINAL_COLS,
        rows: DEFAULT_TERMINAL_ROWS,
        cwd: session.workdir,
        env,
      })
      session.process = ptyProcess
      session.pid = ptyProcess.pid
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err)
      const stack = err instanceof Error ? err.stack : undefined

      // Classify the error for actionable diagnostics
      let hint = ''
      if (msg.includes('ENOENT') || msg.includes('not found')) {
        hint = `Command "${session.command}" not found. Is it installed and on PATH?`
      } else if (msg.includes('EACCES') || msg.includes('permission')) {
        hint = `Permission denied running "${session.command}". Check file permissions.`
      } else if (msg.includes('EIO') || msg.includes('pty') || msg.includes('openpty')) {
        hint = `PTY allocation failed at OS level. Max PTYs reached? Check: sysctl kern.tty.ptmx_max (macOS) or /proc/sys/kernel/pty/max (Linux).`
      } else if (msg.includes('bun-pty') || msg.includes('native') || msg.includes('dlopen')) {
        hint = `bun-pty native module failed to load. Was it compiled for this platform? Try: cd opencode-pty && bun install`
      }

      const diagnostics = [
        `[PTY spawn FAILED]`,
        `  Error: ${msg}`,
        hint ? `  Hint: ${hint}` : null,
        `  Context: ${JSON.stringify(spawnContext)}`,
        stack ? `  Stack: ${stack.split('\n').slice(0, 5).join('\n    ')}` : null,
      ]
        .filter(Boolean)
        .join('\n')

      console.error(diagnostics)
      throw new Error(diagnostics)
    }
  }

  private setupEventHandlers(
    session: PTYSession,
    onData: (session: PTYSession, data: string) => void,
    onExit: (session: PTYSession, exitCode: number | null) => void
  ): void {
    session.process?.onData((data: string) => {
      session.buffer.append(data)
      onData(session, data)
    })

    session.process?.onExit(({ exitCode, signal }) => {
      // Flush any remaining incomplete line in the buffer
      session.buffer.flush()

      if (session.status === 'killing') {
        session.status = 'killed'
      } else {
        session.status = 'exited'
      }
      session.exitCode = exitCode
      session.exitSignal = signal
      onExit(session, exitCode)
    })
  }

  async spawn(
    opts: SpawnOptions,
    onData: (session: PTYSession, data: string) => void,
    onExit: (session: PTYSession, exitCode: number | null) => void
  ): Promise<PTYSessionInfo> {
    const session = this.createSessionObject(opts)
    await this.spawnProcess(session)
    this.setupEventHandlers(session, onData, onExit)
    this.sessions.set(session.id, session)
    return this.toInfo(session)
  }

  kill(id: string, cleanup: boolean = false): boolean {
    const session = this.sessions.get(id)
    if (!session) {
      return false
    }

    if (session.status === 'running') {
      session.status = 'killing'
      try {
        session.process?.kill()
      } catch {
        // Ignore kill errors
      }
    }

    if (cleanup) {
      session.buffer.clear()
      this.sessions.delete(id)
    }

    return true
  }

  private clearAllSessionsInternal(): void {
    for (const id of [...this.sessions.keys()]) {
      this.kill(id, true)
    }
  }

  clearAllSessions(): void {
    this.clearAllSessionsInternal()
  }

  cleanupBySession(parentSessionId: string): void {
    for (const [id, session] of this.sessions) {
      if (session.parentSessionId === parentSessionId) {
        this.kill(id, true)
      }
    }
  }

  getSession(id: string): PTYSession | null {
    return this.sessions.get(id) || null
  }

  listSessions(): PTYSession[] {
    return Array.from(this.sessions.values())
  }

  toInfo(session: PTYSession): PTYSessionInfo {
    return {
      id: session.id,
      title: session.title,
      description: session.description,
      command: session.command,
      args: session.args,
      workdir: session.workdir,
      status: session.status,
      exitCode: session.exitCode,
      exitSignal: session.exitSignal,
      pid: session.pid,
      createdAt: session.createdAt,
      lineCount: session.buffer.length,
    }
  }
}

import { tool } from '@opencode-ai/plugin'
import { manager } from '../manager.ts'
import { buildSessionNotFoundError } from '../utils.ts'
import DESCRIPTION from './kill.txt'

export const ptyKill = tool({
  description: DESCRIPTION,
  args: {
    id: tool.schema.string().describe('The PTY session ID (e.g., pty_a1b2c3d4)'),
    cleanup: tool.schema
      .boolean()
      .optional()
      .describe('If true, removes the session and frees the buffer (default: false)'),
  },
  async execute(args) {
    const session = manager.get(args.id)
    if (!session) {
      throw buildSessionNotFoundError(args.id)
    }

    const wasRunning = session.status === 'running'
    const cleanup = args.cleanup ?? false
    const success = await manager.kill(args.id, cleanup)

    if (!success) {
      throw new Error(`Failed to kill PTY session '${args.id}'.`)
    }

    const action = wasRunning ? 'Killed' : 'Cleaned up'
    const cleanupNote = cleanup ? ' (session removed)' : ' (session retained for log access)'

    const inner = [
      `<pty_killed>`,
      `${action}: ${args.id}${cleanupNote}`,
      `Title: ${session.title}`,
      `Command: ${session.command} ${session.args.join(' ')}`,
      `Final line count: ${session.lineCount}`,
      `</pty_killed>`,
    ].join('\n')

    return `<kortix_system type="pty-kill" source="opencode-pty">\n${inner}\n</kortix_system>`
  },
})

