import { tool } from '@opencode-ai/plugin'
import { manager } from '../manager.ts'
import { DEFAULT_READ_LIMIT, MAX_LINE_LENGTH } from '../../../shared/constants.ts'
import { buildSessionNotFoundError } from '../utils.ts'
import { formatLine } from '../formatters.ts'
import type { PTYSessionInfo } from '../types.ts'
import DESCRIPTION from './read.txt'

interface ReadArgs {
  id: string
  offset?: number
  limit?: number
  pattern?: string
  ignoreCase?: boolean
}

/**
 * Formats PTY output with XML tags and pagination
 */
function formatPtyOutput(
  id: string,
  status: string,
  pattern: string | undefined,
  formattedLines: string[],
  hasMore: boolean,
  paginationMessage: string,
  endMessage: string
): string {
  const inner = [
    `<pty_output id="${id}" status="${status}"${pattern ? ` pattern="${pattern}"` : ''}>`,
    ...formattedLines,
    '',
    hasMore ? paginationMessage : endMessage,
    `</pty_output>`,
  ].join('\n')

  // Wrap in kortix_system tags so frontend renders as system/internal component
  return `<kortix_system type="pty-output" source="opencode-pty">\n${inner}\n</kortix_system>`
}

/**
 * Validates and creates a RegExp from pattern string
 */
function validateAndCreateRegex(pattern: string, ignoreCase?: boolean): RegExp {
  if (!validateRegex(pattern)) {
    throw new Error(
      `Potentially dangerous regex pattern rejected: '${pattern}'. Please use a safer pattern.`
    )
  }

  try {
    return new RegExp(pattern, ignoreCase ? 'i' : '')
  } catch (e) {
    const error = e instanceof Error ? e.message : String(e)
    throw new Error(`Invalid regex pattern '${pattern}': ${error}`)
  }
}

/**
 * Handles pattern-based reading and formatting
 */
function handlePatternRead(
  id: string,
  pattern: string,
  ignoreCase: boolean | undefined,
  session: PTYSessionInfo,
  offset: number,
  limit: number
): string {
  const regex = validateAndCreateRegex(pattern, ignoreCase)

  const result = manager.search(id, regex, offset, limit)
  if (!result) {
    throw buildSessionNotFoundError(id)
  }

  if (result.matches.length === 0) {
    const inner = [
      `<pty_output id="${id}" status="${session.status}" pattern="${pattern}">`,
      `No lines matched the pattern '${pattern}'.`,
      `Total lines in buffer: ${result.totalLines}`,
      `</pty_output>`,
    ].join('\n')
    return `<kortix_system type="pty-output" source="opencode-pty">\n${inner}\n</kortix_system>`
  }

  const formattedLines = result.matches.map((match) =>
    formatLine(match.text, match.lineNumber, MAX_LINE_LENGTH)
  )

  const paginationMessage = `(${result.matches.length} of ${result.totalMatches} matches shown. Use offset=${offset + result.matches.length} to see more.)`
  const endMessage = `(${result.totalMatches} match${result.totalMatches === 1 ? '' : 'es'} from ${result.totalLines} total lines)`

  return formatPtyOutput(
    id,
    session.status,
    pattern,
    formattedLines,
    result.hasMore,
    paginationMessage,
    endMessage
  )
}

/**
 * Handles plain reading and formatting
 */
function handlePlainRead(
  args: ReadArgs,
  session: PTYSessionInfo,
  offset: number,
  limit: number
): string {
  const result = manager.read(args.id, offset, limit)
  if (!result) {
    throw buildSessionNotFoundError(args.id)
  }

  if (result.lines.length === 0) {
    const inner = [
      `<pty_output id="${args.id}" status="${session.status}">`,
      `(No output available - buffer is empty)`,
      `Total lines: ${result.totalLines}`,
      `</pty_output>`,
    ].join('\n')
    return `<kortix_system type="pty-output" source="opencode-pty">\n${inner}\n</kortix_system>`
  }

  const formattedLines = result.lines.map((line, index) =>
    formatLine(line, result.offset + index + 1, MAX_LINE_LENGTH)
  )

  const paginationMessage = `(Buffer has more lines. Use offset=${result.offset + result.lines.length} to read beyond line ${result.offset + result.lines.length})`
  const endMessage = `(End of buffer - total ${result.totalLines} lines)`

  return formatPtyOutput(
    args.id,
    session.status,
    undefined,
    formattedLines,
    result.hasMore,
    paginationMessage,
    endMessage
  )
}

/**
 * Formats a single line with line number and truncation
 */
function validateRegex(pattern: string): boolean {
  try {
    new RegExp(pattern)
    // Check for potentially dangerous patterns that can cause exponential backtracking
    // This is a basic check - more sophisticated validation could be added
    const dangerousPatterns = [
      /\(\?:.*\)\*.*\(\?:.*\)\*/, // nested optional groups with repetition
      /.*\(\.\*\?\)\{2,\}.*/, // overlapping non-greedy quantifiers
      /.*\(.*\|.*\)\{3,\}.*/, // complex alternation with repetition
    ]
    return !dangerousPatterns.some((dangerous) => dangerous.test(pattern))
  } catch {
    return false
  }
}

export const ptyRead = tool({
  description: DESCRIPTION,
  args: {
    id: tool.schema.string().describe('The PTY session ID (e.g., pty_a1b2c3d4)'),
    offset: tool.schema
      .number()
      .optional()
      .describe(
        'Line number to start reading from (0-based, defaults to 0). When using pattern, this applies to filtered matches.'
      ),
    limit: tool.schema
      .number()
      .optional()
      .describe(
        'Number of lines to read (defaults to 500). When using pattern, this applies to filtered matches.'
      ),
    pattern: tool.schema
      .string()
      .optional()
      .describe(
        'Regex pattern to filter lines. When set, only matching lines are returned, then offset/limit apply to the matches.'
      ),
    ignoreCase: tool.schema
      .boolean()
      .optional()
      .describe('Case-insensitive pattern matching (default: false)'),
  },
  async execute(args) {
    const session = manager.get(args.id)
    if (!session) {
      throw buildSessionNotFoundError(args.id)
    }

    const offset = args.offset ?? 0
    const limit = args.limit ?? DEFAULT_READ_LIMIT

    if (args.pattern) {
      return handlePatternRead(args.id, args.pattern, args.ignoreCase, session, offset, limit)
    } else {
      return handlePlainRead(args, session, offset, limit)
    }
  },
})

import { tool } from '@opencode-ai/plugin'
import { manager } from '../manager.ts'
import { checkCommandPermission, checkWorkdirPermission } from '../permissions.ts'
import DESCRIPTION from './spawn.txt'

export const ptySpawn = tool({
  description: DESCRIPTION,
  args: {
    command: tool.schema.string().describe('The command/executable to run'),
    args: tool.schema.array(tool.schema.string()).describe('Arguments to pass to the command'),
    workdir: tool.schema.string().optional().describe('Working directory for the PTY session'),
    env: tool.schema
      .record(tool.schema.string(), tool.schema.string())
      .optional()
      .describe('Additional environment variables'),
    title: tool.schema.string().optional().describe('Human-readable title for the session'),
    description: tool.schema
      .string()
      .describe('Clear, concise description of what this PTY session is for in 5-10 words'),
    notifyOnExit: tool.schema
      .boolean()
      .optional()
      .describe(
        'If true, sends a notification to the session when the process exits (default: false)'
      ),
  },
  async execute(args, ctx) {
    try {
      await checkCommandPermission(args.command, args.args ?? [])

      if (args.workdir) {
        await checkWorkdirPermission(args.workdir)
      }

      const sessionId = ctx.sessionID
      const info = await manager.spawn({
        command: args.command,
        args: args.args,
        workdir: args.workdir,
        env: args.env,
        title: args.title,
        description: args.description,
        parentSessionId: sessionId,
        parentAgent: ctx.agent,
        notifyOnExit: args.notifyOnExit,
      })

      const inner = [
        `ID: ${info.id}`,
        `Title: ${info.title}`,
        `Command: ${info.command} ${info.args.join(' ')}`,
        `Workdir: ${info.workdir}`,
        `PID: ${info.pid}`,
        `Status: ${info.status}`,
      ].join('\n')

      // Wrap in kortix_system tags so frontend renders as system/internal component
      return `<kortix_system type="pty-spawn" source="opencode-pty">\n<pty_spawned>\n${inner}\n</pty_spawned>\n</kortix_system>`
    } catch (err: unknown) {
      // Re-throw permission errors as-is (they have good messages already)
      if (err instanceof Error && err.message.includes('PTY spawn denied')) {
        throw err
      }
      // Re-throw our own diagnostics as-is
      if (err instanceof Error && err.message.includes('[PTY spawn')) {
        throw err
      }

      // Wrap unexpected errors with context
      const msg = err instanceof Error ? err.message : String(err)
      const stack = err instanceof Error ? err.stack : undefined
      throw new Error(
        [
          `[pty_spawn] Failed to spawn PTY session.`,
          `  Command: ${args.command} ${(args.args ?? []).join(' ')}`,
          `  Workdir: ${args.workdir ?? '(default)'}`,
          `  Error: ${msg}`,
          stack ? `  Stack: ${stack.split('\n').slice(1, 4).join('\n    ')}` : null,
        ]
          .filter(Boolean)
          .join('\n')
      )
    }
  },
})

import { tool } from '@opencode-ai/plugin'
import { manager } from '../manager.ts'
import { checkCommandPermission } from '../permissions.ts'
import { buildSessionNotFoundError } from '../utils.ts'
import DESCRIPTION from './write.txt'

const ETX = String.fromCharCode(3)
const EOT = String.fromCharCode(4)

/**
 * Parse escape sequences in a string to their actual byte values.
 * Handles: \n, \r, \t, \xNN (hex), \uNNNN (unicode), \\
 */
function parseEscapeSequences(input: string): string {
  return input.replace(/\\(x[0-9A-Fa-f]{2}|u[0-9A-Fa-f]{4}|[nrt\\])/g, (match, seq: string) => {
    if (seq.startsWith('x')) {
      return String.fromCharCode(parseInt(seq.slice(1), 16))
    }
    if (seq.startsWith('u')) {
      return String.fromCharCode(parseInt(seq.slice(1), 16))
    }
    switch (seq) {
      case 'n':
        return '\n'
      case 'r':
        return '\r'
      case 't':
        return '\t'
      case '\\':
        return '\\'
      default:
        return match
    }
  })
}

function extractCommands(data: string): string[] {
  const commands: string[] = []
  const lines = data.split(/[\n\r]+/)
  for (const line of lines) {
    const trimmed = line.trim()
    if (trimmed && !trimmed.startsWith(ETX) && !trimmed.startsWith(EOT)) {
      commands.push(trimmed)
    }
  }
  return commands
}

function parseCommand(commandLine: string): { command: string; args: string[] } {
  const parts = commandLine.split(/\s+/).filter(Boolean)
  const command = parts[0] ?? ''
  const args = parts.slice(1)
  return { command, args }
}

export const ptyWrite = tool({
  description: DESCRIPTION,
  args: {
    id: tool.schema.string().describe('The PTY session ID (e.g., pty_a1b2c3d4)'),
    data: tool.schema.string().describe('The input data to send to the PTY'),
  },
  async execute(args) {
    const session = manager.get(args.id)
    if (!session) {
      throw buildSessionNotFoundError(args.id)
    }

    if (session.status !== 'running') {
      throw new Error(`Cannot write to PTY '${args.id}' - session status is '${session.status}'.`)
    }

    // Parse escape sequences to actual bytes
    const parsedData = parseEscapeSequences(args.data)

    const commands = extractCommands(parsedData)
    for (const commandLine of commands) {
      const { command, args: cmdArgs } = parseCommand(commandLine)
      if (command) {
        await checkCommandPermission(command, cmdArgs)
      }
    }

    const success = await manager.write(args.id, parsedData)
    if (!success) {
      throw new Error(`Failed to write to PTY '${args.id}'.`)
    }

    const preview = args.data.length > 50 ? `${args.data.slice(0, 50)}...` : args.data
    const displayPreview = preview
      .replace(new RegExp(ETX, 'g'), '^C')
      .replace(new RegExp(EOT, 'g'), '^D')
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r')

    const inner = `Sent ${args.data.length} bytes to ${args.id}: "${displayPreview}"`
    return `<kortix_system type="pty-write" source="opencode-pty">\n${inner}\n</kortix_system>`
  },
})

export function buildSessionNotFoundError(id: string): Error {
  return new Error(`PTY session '${id}' not found. Use pty_list to see active sessions.`)
}

/**
 * Helper to DRY up session-get/null-check logic
 * - manager: object with a getSession(id) or similar method
 * - id: session id
 * - fn: function called with session if found
 * - defaultValue: what to return if not found (default null)
 */
export function withSession<TSession, TResult>(
  manager: { getSession(id: string): TSession | null },
  id: string,
  fn: (session: TSession) => TResult,
  defaultValue: TResult
): TResult {
  const session = manager.getSession(id)
  if (!session) return defaultValue
  return fn(session)
}

export function match(str: string, pattern: string): boolean {
  const regex = new RegExp(
    '^' +
      pattern
        .replace(/[.+^${}()|[\]\\]/g, '\\$&')
        .replace(/\*/g, '.*')
        .replace(/\?/g, '.') +
      '$',
    's'
  )
  return regex.test(str)
}

export function all(input: string, patterns: Record<string, string>): string | undefined {
  const sorted = Object.entries(patterns).sort(
    (a, b) => a[0].length - b[0].length || a[0].localeCompare(b[0])
  )
  let result: string | undefined
  for (const [pattern, value] of sorted) {
    if (match(input, pattern)) {
      result = value
    }
  }
  return result
}

export function allStructured(
  input: { head: string; tail: string[] },
  patterns: Record<string, string>
): string | undefined {
  const sorted = Object.entries(patterns).sort(
    (a, b) => a[0].length - b[0].length || a[0].localeCompare(b[0])
  )
  let result: string | undefined
  for (const [pattern, value] of sorted) {
    const parts = pattern.split(/\s+/)
    const firstPart = parts[0]
    if (!firstPart || !match(input.head, firstPart)) continue
    if (parts.length === 1 || matchSequence(input.tail, parts.slice(1))) {
      result = value
    }
  }
  return result
}

function matchSequence(items: string[], patterns: string[]): boolean {
  if (patterns.length === 0) return true
  const [pattern, ...rest] = patterns
  if (pattern === '*') return matchSequence(items, rest)
  for (let i = 0; i < items.length; i++) {
    const item = items[i]
    if (
      item !== undefined &&
      pattern !== undefined &&
      match(item, pattern) &&
      matchSequence(items.slice(i + 1), rest)
    ) {
      return true
    }
  }
  return false
}

// Shared constants used across the entire application
export const DEFAULT_READ_LIMIT = 500
export const MAX_LINE_LENGTH = 2000
export const DEFAULT_MAX_BUFFER_LINES = 50000

// Performance monitoring constants
export const PERFORMANCE_MEASURE_LIMIT = 100

import { type Plugin, tool } from '@opencode-ai/plugin'
import { DEFAULT_READ_LIMIT, MAX_LINE_LENGTH } from './opencode-pty/src/shared/constants.ts'
import { formatLine, formatSessionInfo } from './opencode-pty/src/plugin/pty/formatters.ts'
import { initPermissions, checkCommandPermission, checkWorkdirPermission } from './opencode-pty/src/plugin/pty/permissions.ts'
import { initManager, manager } from './opencode-pty/src/plugin/pty/manager.ts'

const ETX = String.fromCharCode(3)
const EOT = String.fromCharCode(4)

function notFound(id: string): Error {
  return new Error(`PTY session '${id}' not found. Use pty_list to see active sessions.`)
}

function parseEscapeSequences(input: string): string {
  return input.replace(/\\(x[0-9A-Fa-f]{2}|u[0-9A-Fa-f]{4}|[nrt\\])/g, (match, seq: string) => {
    if (seq.startsWith('x')) return String.fromCharCode(parseInt(seq.slice(1), 16))
    if (seq.startsWith('u')) return String.fromCharCode(parseInt(seq.slice(1), 16))
    switch (seq) {
      case 'n': return '\n'
      case 'r': return '\r'
      case 't': return '\t'
      case '\\': return '\\'
      default: return match
    }
  })
}

function extractCommands(data: string): string[] {
  return data
    .split(/[\n\r]+/)
    .map((line) => line.trim())
    .filter((line) => line && !line.startsWith(ETX) && !line.startsWith(EOT))
}

function parseCommand(commandLine: string): { command: string; args: string[] } {
  const parts = commandLine.split(/\s+/).filter(Boolean)
  return { command: parts[0] ?? '', args: parts.slice(1) }
}

function validateRegex(pattern: string): boolean {
  try {
    new RegExp(pattern)
    const dangerousPatterns = [
      /\(\?:.*\)\*.*\(\?:.*\)\*/,
      /.*\(\.\*\?\)\{2,\}.*/,
      /.*\(.*\|.*\)\{3,\}.*/,
    ]
    return !dangerousPatterns.some((dangerous) => dangerous.test(pattern))
  } catch {
    return false
  }
}

function buildPtyOutput(
  id: string,
  status: string,
  lines: string[],
  footer: string,
  pattern?: string,
): string {
  const inner = [
    `<pty_output id="${id}" status="${status}"${pattern ? ` pattern="${pattern}"` : ''}>`,
    ...lines,
    '',
    footer,
    `</pty_output>`,
  ].join('\n')
  return `<kortix_system type="pty-output" source="opencode-pty">\n${inner}\n</kortix_system>`
}

const PtyToolsPlugin: Plugin = async ({ client, directory, serverUrl }) => {
  console.log('[pty-tools] plugin init')
  initPermissions(client, directory)
  initManager(client, serverUrl, directory)
  manager.probe().catch(() => undefined)

  return {
    tool: {
      pty_spawn: tool({
        description: 'Spawn a background PTY session for a long-running or interactive command.',
        args: {
          command: tool.schema.string().describe('Command/executable to run'),
          args: tool.schema.array(tool.schema.string()).optional().describe('Arguments to pass to the command'),
          workdir: tool.schema.string().optional().describe('Working directory for the PTY session'),
          env: tool.schema.object({}).catchall(tool.schema.string()).optional().describe('Additional environment variables'),
          title: tool.schema.string().optional().describe('Human-readable title for the session'),
          description: tool.schema.string().describe('Clear, concise 5-10 word description'),
          notifyOnExit: tool.schema.boolean().optional().describe('Notify when the process exits'),
        },
        async execute(args, ctx) {
          await checkCommandPermission(args.command, args.args ?? [])
          if (args.workdir) await checkWorkdirPermission(args.workdir)
          const info = await manager.spawn({
            command: args.command,
            args: args.args,
            workdir: args.workdir,
            env: args.env,
            title: args.title,
            description: args.description,
            parentSessionId: ctx.sessionID,
            parentAgent: ctx.agent,
            notifyOnExit: args.notifyOnExit,
          })
          const inner = [
            'ID: ' + info.id,
            'Title: ' + info.title,
            `Command: ${info.command} ${info.args.join(' ')}`,
            'Workdir: ' + info.workdir,
            'PID: ' + info.pid,
            'Status: ' + info.status,
          ].join('\n')
          return `<kortix_system type="pty-spawn" source="opencode-pty">\n<pty_spawned>\n${inner}\n</pty_spawned>\n</kortix_system>`
        },
      }),

      pty_write: tool({
        description: 'Send input to a running PTY session.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          data: tool.schema.string().describe('Input data to send to the PTY'),
        },
        async execute(args) {
          const session = manager.get(args.id)
          if (!session) throw notFound(args.id)
          if (session.status !== 'running') {
            throw new Error(`Cannot write to PTY '${args.id}' - session status is '${session.status}'.`)
          }
          const parsedData = parseEscapeSequences(args.data)
          for (const commandLine of extractCommands(parsedData)) {
            const { command, args: cmdArgs } = parseCommand(commandLine)
            if (command) await checkCommandPermission(command, cmdArgs)
          }
          const success = await manager.write(args.id, parsedData)
          if (!success) throw new Error(`Failed to write to PTY '${args.id}'.`)
          const preview = args.data.length > 50 ? `${args.data.slice(0, 50)}...` : args.data
          const displayPreview = preview
            .replace(new RegExp(ETX, 'g'), '^C')
            .replace(new RegExp(EOT, 'g'), '^D')
            .replace(/\n/g, '\\n')
            .replace(/\r/g, '\\r')
          return `<kortix_system type="pty-write" source="opencode-pty">\nSent ${args.data.length} bytes to ${args.id}: "${displayPreview}"\n</kortix_system>`
        },
      }),

      pty_read: tool({
        description: 'Read PTY output with pagination and optional regex filtering.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          offset: tool.schema.number().optional().describe('0-based starting line/match offset'),
          limit: tool.schema.number().optional().describe('Maximum number of lines/matches to return'),
          pattern: tool.schema.string().optional().describe('Regex filter applied before pagination'),
          ignoreCase: tool.schema.boolean().optional().describe('Case-insensitive regex matching'),
        },
        async execute(args) {
          const session = manager.get(args.id)
          if (!session) throw notFound(args.id)
          const offset = args.offset ?? 0
          const limit = args.limit ?? DEFAULT_READ_LIMIT

          if (args.pattern) {
            if (!validateRegex(args.pattern)) {
              throw new Error(`Potentially dangerous regex pattern rejected: '${args.pattern}'. Please use a safer pattern.`)
            }
            const regex = new RegExp(args.pattern, args.ignoreCase ? 'i' : '')
            const result = manager.search(args.id, regex, offset, limit)
            if (!result) throw notFound(args.id)
            if (result.matches.length === 0) {
              return `<kortix_system type="pty-output" source="opencode-pty">\n<pty_output id="${args.id}" status="${session.status}" pattern="${args.pattern}">\nNo lines matched the pattern '${args.pattern}'.\nTotal lines in buffer: ${result.totalLines}\n</pty_output>\n</kortix_system>`
            }
            const lines = result.matches.map((match) => formatLine(match.text, match.lineNumber, MAX_LINE_LENGTH))
            const footer = result.hasMore
              ? `(${result.matches.length} of ${result.totalMatches} matches shown. Use offset=${offset + result.matches.length} to see more.)`
              : `(${result.totalMatches} match${result.totalMatches === 1 ? '' : 'es'} from ${result.totalLines} total lines)`
            return buildPtyOutput(args.id, session.status, lines, footer, args.pattern)
          }

          const result = manager.read(args.id, offset, limit)
          if (!result) throw notFound(args.id)
          if (result.lines.length === 0) {
            return `<kortix_system type="pty-output" source="opencode-pty">\n<pty_output id="${args.id}" status="${session.status}">\n(No output available - buffer is empty)\nTotal lines: ${result.totalLines}\n</pty_output>\n</kortix_system>`
          }
          const lines = result.lines.map((line, index) => formatLine(line, result.offset + index + 1, MAX_LINE_LENGTH))
          const footer = result.hasMore
            ? `(Buffer has more lines. Use offset=${result.offset + result.lines.length} to read beyond line ${result.offset + result.lines.length})`
            : `(End of buffer - total ${result.totalLines} lines)`
          return buildPtyOutput(args.id, session.status, lines, footer)
        },
      }),

      pty_list: tool({
        description: 'List active PTY sessions.',
        args: {},
        async execute() {
          const sessions = await manager.list()
          if (sessions.length === 0) {
            return `<kortix_system type="pty-list" source="opencode-pty">\n<pty_list>\nNo active PTY sessions.\n</pty_list>\n</kortix_system>`
          }
          const inner = ['<pty_list>', ...sessions.flatMap((session) => formatSessionInfo(session)), `Total: ${sessions.length} session(s)`, '</pty_list>'].join('\n')
          return `<kortix_system type="pty-list" source="opencode-pty">\n${inner}\n</kortix_system>`
        },
      }),

      pty_kill: tool({
        description: 'Terminate a PTY session and optionally clean it up.',
        args: {
          id: tool.schema.string().describe('PTY session ID'),
          cleanup: tool.schema.boolean().optional().describe('If true, remove the cached session data too'),
        },
        async execute(args) {
          const session = manager.get(args.id)
          if (!session) throw notFound(args.id)
          const wasRunning = session.status === 'running'
          const cleanup = args.cleanup ?? false
          const success = await manager.kill(args.id, cleanup)
          if (!success) throw new Error(`Failed to kill PTY session '${args.id}'.`)
          const action = wasRunning ? 'Killed' : 'Cleaned up'
          const cleanupNote = cleanup ? ' (session removed)' : ' (session retained for log access)'
          const inner = [
            '<pty_killed>',
            `${action}: ${args.id}${cleanupNote}`,
            `Title: ${session.title}`,
            `Command: ${session.command} ${session.args.join(' ')}`,
            `Final line count: ${session.lineCount}`,
            '</pty_killed>',
          ].join('\n')
          return `<kortix_system type="pty-kill" source="opencode-pty">\n${inner}\n</kortix_system>`
        },
      }),
    },
    event: async ({ event }) => {
      if (event.type === 'session.deleted') manager.cleanupBySession(event.properties.info.id)
    },
  }
}

export default PtyToolsPlugin

import { tool } from "@opencode-ai/plugin";
import Replicate from "replicate";
import { getEnv, getKortixRouterBase } from "./lib/get-env";

const SERPER_DEFAULT_URL = "https://google.serper.dev";

function getSerperImagesUrl(): string {
  const override = getKortixRouterBase("serper");
  const base = override || SERPER_DEFAULT_URL;
  return `${base.replace(/\/+$/, "")}/images`;
}
const MOONDREAM_MODEL =
  "lucataco/moondream2:72ccb656353c348c1385df54b237eeb7bfa874bf11486cf0b9473e691b662d31";
const MOONDREAM_PROMPT =
  "Describe this image in detail. Include any text visible in the image.";
const IMAGE_DOWNLOAD_TIMEOUT_MS = 15_000;

interface SerperImage {
  imageUrl: string;
  title?: string;
  link?: string;
  imageWidth?: number;
  imageHeight?: number;
}

interface SerperResponse {
  images?: SerperImage[];
  searchParameters?: Record<string, unknown>;
}

interface EnrichedImage {
  url: string;
  title: string;
  source: string;
  width: number;
  height: number;
  description: string;
}

function extractImages(data: SerperResponse): EnrichedImage[] {
  return (data.images ?? []).map((img) => ({
    url: img.imageUrl,
    title: img.title ?? "",
    source: img.link ?? "",
    width: img.imageWidth ?? 0,
    height: img.imageHeight ?? 0,
    description: "",
  }));
}

async function describeImage(
  replicate: Replicate,
  imageUrl: string,
): Promise<string> {
  try {
    const res = await fetch(imageUrl, {
      headers: {
        "User-Agent":
          "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36",
      },
      signal: AbortSignal.timeout(IMAGE_DOWNLOAD_TIMEOUT_MS),
      redirect: "follow",
    });

    if (!res.ok) return "";
    const contentType = res.headers.get("content-type") ?? "";
    if (!contentType.startsWith("image/")) return "";

    const imageBytes = await res.arrayBuffer();
    const b64 = Buffer.from(imageBytes).toString("base64");
    const dataUrl = `data:${contentType};base64,${b64}`;

    const output: unknown = await replicate.run(MOONDREAM_MODEL, {
      input: { image: dataUrl, prompt: MOONDREAM_PROMPT },
    });

    if (typeof output === "string") return output.trim();
    if (output && typeof output === "object" && Symbol.iterator in output) {
      return Array.from(output as Iterable<unknown>)
        .map(String)
        .join("")
        .trim();
    }
    return "";
  } catch {
    return "";
  }
}

async function enrichImages(images: EnrichedImage[]): Promise<EnrichedImage[]> {
  const replicateBaseUrl = getKortixRouterBase("replicate") ?? undefined;
  // Route through the Kortix router (derived from KORTIX_API_URL); auth with
  // KORTIX_TOKEN. Fall back to a raw REPLICATE_API_TOKEN only when unset.
  const replicateToken = replicateBaseUrl
    ? getEnv("KORTIX_TOKEN")
    : getEnv("REPLICATE_API_TOKEN");
  if (!replicateToken || images.length === 0) return images;

  const replicate = new Replicate({
    auth: replicateToken,
    ...(replicateBaseUrl ? { baseUrl: replicateBaseUrl } : {}),
  });

  return Promise.all(
    images.map(async (img) => {
      try {
        const description = await describeImage(replicate, img.url);
        return { ...img, description: description || img.description };
      } catch {
        return img;
      }
    }),
  );
}

export default tool({
  description:
    "Search for images using the Serper Google Images API. " +
    "Returns image URLs with titles, source pages, dimensions, and AI-generated descriptions. " +
    "When REPLICATE_API_TOKEN is set, enriches results with Moondream2 vision descriptions. " +
    "Supports batch queries separated by |||. " +
    "Use specific descriptive queries including topic/brand names for best results.",
  args: {
    query: tool.schema
      .string()
      .describe(
        "Image search query. For batch, separate with ||| (e.g. 'cats ||| dogs')",
      ),
    num_results: tool.schema
      .number()
      .optional()
      .describe("Images per query (1-100). Default: 12"),
    enrich: tool.schema
      .boolean()
      .optional()
      .describe(
        "Enrich images with AI descriptions via Moondream2. Requires REPLICATE_API_TOKEN. Default: true",
      ),
  },
  async execute(args, _context) {
    const serperUrlOverride = getKortixRouterBase("serper") ?? undefined;
    // Route through the Kortix router (derived from KORTIX_API_URL); auth with
    // KORTIX_TOKEN. Fall back to a raw SERPER_API_KEY only when unset.
    const apiKey = serperUrlOverride
      ? getEnv("KORTIX_TOKEN")
      : getEnv("SERPER_API_KEY");
    if (!apiKey) return serperUrlOverride
      ? "Error: KORTIX_TOKEN not set."
      : "Error: SERPER_API_KEY not set.";

    const numResults = Math.max(1, Math.min(args.num_results ?? 12, 100));
    const shouldEnrich = args.enrich !== false;
    const queries = args.query
      .split("|||")
      .map((q) => q.trim())
      .filter(Boolean);
    if (queries.length === 0) return "Error: empty query.";

    const headers = {
      "X-API-KEY": apiKey,
      "Content-Type": "application/json",
    };

    try {
      if (queries.length === 1) {
        const res = await fetch(getSerperImagesUrl(), {
          method: "POST",
          headers,
          body: JSON.stringify({ q: queries[0], num: numResults }),
        });
        if (!res.ok)
          return `Error: Serper API returned ${res.status}: ${await res.text()}`;

        const data = (await res.json()) as SerperResponse;
        let images = extractImages(data);

        if (images.length === 0) return `No images found for: '${queries[0]}'`;
        if (shouldEnrich) images = await enrichImages(images);

        return JSON.stringify(
          { query: queries[0], total: images.length, images },
          null,
          2,
        );
      }

      const payload = queries.map((q) => ({ q, num: numResults }));
      const res = await fetch(getSerperImagesUrl(), {
        method: "POST",
        headers,
        body: JSON.stringify(payload),
      });
      if (!res.ok)
        return `Error: Serper API returned ${res.status}: ${await res.text()}`;

      const data = await res.json();
      const dataArr: SerperResponse[] = Array.isArray(data) ? data : [data];

      const results = await Promise.all(
        dataArr.map(async (d, i) => {
          let images = extractImages(d);
          if (shouldEnrich) images = await enrichImages(images);
          return { query: queries[i], total: images.length, images };
        }),
      );

      return JSON.stringify({ batch_mode: true, results }, null, 2);
    } catch (e) {
      return `Error: ${String(e)}`;
    }
  },
});

import { readFileSync, existsSync } from "fs";
import { resolve, dirname } from "path";

const S6_ENV_DIR =
  process.env.S6_ENV_DIR || "/run/s6/container_environment";

/**
 * Parsed .env file cache.
 * Loaded once on first miss, never re-read (process lifetime).
 */
let dotenvCache: Record<string, string> | null = null;

/**
 * Walk up from multiple starting points to find the nearest .env file.
 * Tries both __dirname-based path and process.cwd() to handle bundled
 * and native execution contexts.
 */
function findDotenvPath(): string | null {
  // Try multiple starting points — __dirname may differ when bundled
  const startDirs = [
    dirname(dirname(__dirname)),  // tools/lib/ → tools/ → OpenCode config dir
    process.cwd(),                // wherever OpenCode was started from
  ];

  for (const start of startDirs) {
    let dir = start;
    for (let i = 0; i < 5; i++) {
      const candidate = resolve(dir, ".env");
      if (existsSync(candidate)) return candidate;
      const parent = dirname(dir);
      if (parent === dir) break; // filesystem root
      dir = parent;
    }
  }
  return null;
}

/**
 * Parse a .env file into a key→value map.
 * Supports KEY=VALUE, ignores comments (#) and blank lines.
 * Does NOT handle multi-line values or quoted values with newlines.
 */
function parseDotenv(path: string): Record<string, string> {
  const result: Record<string, string> = {};
  try {
    const content = readFileSync(path, "utf-8");
    for (const line of content.split("\n")) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith("#")) continue;
      const eqIdx = trimmed.indexOf("=");
      if (eqIdx <= 0) continue;
      const key = trimmed.slice(0, eqIdx).trim();
      let value = trimmed.slice(eqIdx + 1).trim();
      // Strip surrounding quotes if present
      if (
        (value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))
      ) {
        value = value.slice(1, -1);
      }
      if (key && value) result[key] = value;
    }
  } catch {
    // File unreadable — return empty
  }
  return result;
}

/**
 * Load the .env cache (once per process).
 */
function getDotenv(): Record<string, string> {
  if (dotenvCache !== null) return dotenvCache;
  const path = findDotenvPath();
  dotenvCache = path ? parseDotenv(path) : {};
  return dotenvCache;
}

/**
 * Read an environment variable with multi-tier fallback.
 *
 * Resolution order (first non-empty wins):
 *
 * 1. s6 env dir file     — `/run/s6/container_environment/{key}` (always fresh, ~1μs tmpfs read)
 * 2. `process.env[key]`  — Docker env, manually exported (native dev without s6)
 * 3. `.env` file          — nearest `.env` walking up from the OpenCode config dir (native dev fallback)
 *
 * s6 is checked first so that env var updates from the secrets manager
 * (kortix-master /env API) take effect immediately — no service restart needed.
 * In native dev (no s6 dir), the read throws and falls through to process.env.
 */
export function getEnv(key: string): string | undefined {
  // 1. s6 env dir — authoritative in containers, always fresh from disk.
  //    kortix-master writes here on every /env POST, so values update without restart.
  //    tmpfs read is ~1μs — negligible cost for always-correct values.
  try {
    const val = readFileSync(`${S6_ENV_DIR}/${key}`, "utf-8").trim();
    if (val) return val;
  } catch {
    // File doesn't exist — not in a container, or key not set via s6.
  }

  // 2. process.env — Docker env vars, shell exports (native dev without s6)
  const fromEnv = process.env[key];
  if (fromEnv) return fromEnv;

  // 3. .env file fallback (native dev on macOS — no Docker, no s6)
  const dotenv = getDotenv();
  const envVal = dotenv[key];
  if (envVal) return envVal;

  return undefined;
}

/**
 * Base URL for a Kortix router-proxied upstream service, derived from
 * KORTIX_API_URL. The sandbox only ever holds KORTIX_API_URL + KORTIX_TOKEN;
 * tools build their proxy endpoint from those two. Normalizes so it works
 * whether KORTIX_API_URL is a bare origin or already ends in /v1 or /v1/router.
 * Returns null when KORTIX_API_URL is unset.
 */
export function getKortixRouterBase(service: string): string | null {
  const raw = getEnv("KORTIX_API_URL");
  if (!raw) return null;
  const root = raw
    .replace(/\/+$/, "")
    .replace(/\/v1\/router$/, "")
    .replace(/\/v1$/, "");
  return `${root}/v1/router/${service}`;
}

import { tool } from "@opencode-ai/plugin";
import FirecrawlApp from "@mendable/firecrawl-js";
import { getEnv, getKortixRouterBase } from "./lib/get-env";

interface ScrapeResult {
  url: string;
  success: boolean;
  title?: string;
  content?: string;
  content_length?: number;
  html?: string;
  metadata?: Record<string, unknown>;
  error?: string;
}

async function scrapeOne(
  client: FirecrawlApp,
  url: string,
  includeHtml: boolean,
  retries = 3,
): Promise<ScrapeResult> {
  const formats: ("markdown" | "html")[] = includeHtml
    ? ["markdown", "html"]
    : ["markdown"];

  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = (await client.scrape(url, {
        formats,
        timeout: 30000,
      })) as Record<string, unknown>;

      const metadata = (response.metadata ?? {}) as Record<string, string>;
      const markdown = (response.markdown ?? "") as string;
      const html = (response.html ?? "") as string;

      const result: ScrapeResult = {
        url,
        success: true,
        title: metadata.title ?? "",
        content: markdown,
        content_length: markdown.length,
      };

      if (includeHtml && html) result.html = html;
      if (Object.keys(metadata).length > 0) result.metadata = metadata;
      return result;
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      const isTimeout = msg.includes("timeout") || msg.includes("Timeout");

      if (isTimeout && attempt < retries) {
        await new Promise((r) => setTimeout(r, 2 ** attempt * 1000));
        continue;
      }
      return { url, success: false, error: msg };
    }
  }
  return { url, success: false, error: "max retries exceeded" };
}

export default tool({
  description:
    "Fetch and extract content from web pages using Firecrawl. " +
    "Converts HTML to clean markdown. " +
    "Supports multiple URLs separated by commas. " +
    "Batch URLs in a single call for efficiency. " +
    "For GitHub URLs, prefer gh CLI via Bash instead.",
  args: {
    urls: tool.schema
      .string()
      .describe(
        "URLs to scrape, comma-separated (e.g. 'https://example.com/a,https://example.com/b')",
      ),
    include_html: tool.schema
      .boolean()
      .optional()
      .describe("Include raw HTML alongside markdown. Default: false"),
  },
  async execute(args, _context) {
    // Route through the Kortix router (derived from KORTIX_API_URL) and auth with
    // KORTIX_TOKEN; the router injects the real upstream key. Fall back to a raw
    // FIRECRAWL_API_KEY only when KORTIX_API_URL is unset (self-host/direct).
    const apiBaseURL = getKortixRouterBase("firecrawl") ?? undefined;
    const apiKey = apiBaseURL
      ? getEnv("KORTIX_TOKEN")
      : getEnv("FIRECRAWL_API_KEY");
    if (!apiKey) return apiBaseURL
      ? "Error: KORTIX_TOKEN not set."
      : "Error: FIRECRAWL_API_KEY not set.";

    const client = new FirecrawlApp({
      apiKey,
      apiUrl: apiBaseURL ?? "https://api.firecrawl.dev",
    });
    const includeHtml = args.include_html ?? false;

    const urlList = args.urls
      .split(",")
      .map((u) => u.trim())
      .filter(Boolean);
    if (urlList.length === 0) return "Error: no valid URLs provided.";

    const results = await Promise.all(
      urlList.map((u) => scrapeOne(client, u, includeHtml)),
    );

    const successful = results.filter((r) => r.success).length;
    const failed = results.length - successful;

    if (successful === 0) {
      const errors = results.map((r) => `${r.url}: ${r.error}`).join("; ");
      return `Error: Failed to scrape all ${results.length} URLs. ${errors}`;
    }

    if (urlList.length === 1) return JSON.stringify(results[0], null, 2);

    return JSON.stringify(
      { total: results.length, successful, failed, results },
      null,
      2,
    );
  },
});

import { tool } from "@opencode-ai/plugin";
import { existsSync } from "fs";
import { resolve } from "path";

// ── Types ──────────────────────────────────────────────────────────────────

/** Content types the show tool can present. */
const TYPES = [
  "file",
  "image",
  "url",
  "text",
  "error",
  "video",
  "audio",
  "code",
  "markdown",
  "pdf",
  "html",
  "csv",
  "xlsx",
  "docx",
  "pptx",
] as const;
type ShowType = (typeof TYPES)[number];

/** Display variants that control how the frontend renders the output. */
const VARIANTS = [
  "compact",   // Minimal inline card — small footprint in the conversation
  "full",      // Full available space — ideal for URL previews, HTML, PDFs
  "gallery",   // Visual-first — centers content with proper aspect ratio
  "detail",    // Rich layout — prominent title, description, content sections
] as const;
type ShowVariant = (typeof VARIANTS)[number];

/** Aspect ratio presets for visual content. */
const ASPECT_RATIOS = [
  "auto",
  "1:1",
  "16:9",
  "9:16",
  "4:3",
  "3:2",
  "21:9",
] as const;
type ShowAspectRatio = (typeof ASPECT_RATIOS)[number];

/** Visual theme for the output card. */
const THEMES = [
  "default",
  "success",
  "warning",
  "info",
  "danger",
] as const;
type ShowTheme = (typeof THEMES)[number];

interface ShowEntry {
  id: string;
  timestamp: string;
  type: ShowType;
  title?: string;
  description?: string;
  path?: string;
  url?: string;
  content?: string;
  variant?: ShowVariant;
  aspect_ratio?: ShowAspectRatio;
  theme?: ShowTheme;
  language?: string;
  metadata?: Record<string, unknown>;
}

function generateId(): string {
  return `show_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

/** Infer a sensible default variant based on content type. */
function defaultVariant(type: ShowType): ShowVariant {
  switch (type) {
    case "url":
    case "html":
    case "pdf":
      return "full";
    case "image":
    case "video":
      return "gallery";
    case "code":
    case "markdown":
    case "text":
      return "detail";
    case "csv":
    case "xlsx":
      return "full";
    case "docx":
    case "pptx":
      return "full";
    case "audio":
    case "file":
      return "compact";
    case "error":
      return "compact";
    default:
      return "detail";
  }
}

// ── Shared validation ──────────────────────────────────────────────────────

const PATH_TYPES: ShowType[] = ["file", "image", "video", "audio", "pdf", "csv", "xlsx", "docx", "pptx"];
const CONTENT_TYPES: ShowType[] = ["text", "error", "code", "markdown", "html"];

function validateAndBuildEntry(item: Record<string, unknown>): string | ShowEntry {
  const type = item.type as ShowType | undefined;
  if (!type || !TYPES.includes(type as ShowType)) {
    return `Error: 'type' is required. Use one of: ${TYPES.join(", ")}.`;
  }

  if (PATH_TYPES.includes(type) && !item.path) {
    return `Error: 'path' is required when type is '${type}'.`;
  }
  if (type === "url" && !item.url) {
    return `Error: 'url' is required when type is 'url'.`;
  }
  if (CONTENT_TYPES.includes(type) && !item.content) {
    return `Error: 'content' is required when type is '${type}'.`;
  }

  if (PATH_TYPES.includes(type) && item.path) {
    const absPath = resolve(item.path as string);
    if (!existsSync(absPath)) {
      return `Error: File not found: ${absPath}`;
    }
  }

  const variant = (item.variant as ShowVariant) || undefined;
  if (variant && !VARIANTS.includes(variant)) {
    return `Error: Invalid variant '${variant}'. Use one of: ${VARIANTS.join(", ")}.`;
  }

  const aspectRatio = (item.aspect_ratio as ShowAspectRatio) || undefined;
  if (aspectRatio && !ASPECT_RATIOS.includes(aspectRatio)) {
    return `Error: Invalid aspect_ratio '${aspectRatio}'. Use one of: ${ASPECT_RATIOS.join(", ")}.`;
  }

  const theme = (item.theme as ShowTheme) || undefined;
  if (theme && !THEMES.includes(theme)) {
    return `Error: Invalid theme '${theme}'. Use one of: ${THEMES.join(", ")}.`;
  }

  let metadata: Record<string, unknown> | undefined;
  if (item.metadata) {
    if (typeof item.metadata === "string") {
      try {
        metadata = JSON.parse(item.metadata);
      } catch {
        return `Error: Invalid JSON in 'metadata' parameter.`;
      }
    } else if (typeof item.metadata === "object") {
      metadata = item.metadata as Record<string, unknown>;
    }
  }

  const resolvedVariant = variant || defaultVariant(type);

  return {
    id: generateId(),
    timestamp: new Date().toISOString(),
    type,
    variant: resolvedVariant,
    ...(item.title ? { title: item.title as string } : {}),
    ...(item.description ? { description: item.description as string } : {}),
    ...(item.path ? { path: resolve(item.path as string) } : {}),
    ...(item.url ? { url: item.url as string } : {}),
    ...(item.content ? { content: item.content as string } : {}),
    ...(aspectRatio ? { aspect_ratio: aspectRatio } : {}),
    ...(theme && theme !== "default" ? { theme } : {}),
    ...(item.language ? { language: item.language as string } : {}),
    ...(metadata ? { metadata } : {}),
  };
}

