 * Whisper Audio Transcription CLI
 *
 * Transcribes audio/video files to text using the fastest available provider:
 *   1. Groq Whisper (fastest — near-instant)
 *   2. OpenAI Whisper (reliable fallback)
 *
 * Usage:
 *   bun run transcribe.ts --file /path/to/audio.ogg
 *   bun run transcribe.ts --file /path/to/audio.mp3 --language en
 *   bun run transcribe.ts --file /path/to/video.mp4 --timestamps
 *
 * Supported: mp3, mp4, mpeg, mpga, m4a, wav, webm, ogg, oga, flac
 * Auth: GROQ_API_KEY (preferred) or OPENAI_API_KEY
 * Output: JSON always.
 */

import { readFileSync, existsSync } from "node:fs"

// ─── Env resolution (s6 → process.env fallback) ─────────────────────────────

function getEnv(key: string): string | undefined {
  // Try common s6 env paths
  for (const dir of [
    process.env.S6_ENV_DIR,
    "/run/s6/container_environment",
    "/var/run/s6/container_environment",
  ]) {
    if (!dir) continue
    try {
      const val = readFileSync(`${dir}/${key}`, "utf-8").trim()
      if (val) return val
    } catch {}
  }
  return process.env[key] || undefined
}

// ─── Transcription ──────────────────────────────────────────────────────────

interface TranscribeOpts {
  file: string
  language?: string
  timestamps?: boolean
  prompt?: string
}

export async function transcribe(opts: TranscribeOpts): Promise<any> {
  const groqKey = getEnv("GROQ_API_KEY")
  const openaiKey = getEnv("OPENAI_API_KEY")

  if (!groqKey && !openaiKey) {
    return { ok: false, error: "No API key. Set GROQ_API_KEY (fastest) or OPENAI_API_KEY." }
  }

  if (!existsSync(opts.file)) {
    return { ok: false, error: `File not found: ${opts.file}` }
  }

  const fileData = readFileSync(opts.file)
  const ext = opts.file.split(".").pop()?.toLowerCase() || "ogg"
  const mimeMap: Record<string, string> = {
    mp3: "audio/mpeg", mp4: "video/mp4", mpeg: "audio/mpeg", mpga: "audio/mpeg",
    m4a: "audio/mp4", wav: "audio/wav", webm: "audio/webm", ogg: "audio/ogg",
    oga: "audio/ogg", flac: "audio/flac",
  }
  const mime = mimeMap[ext] || "audio/ogg"
  const filename = opts.file.split("/").pop() || `audio.${ext}`

  const formData = new FormData()
  formData.append("file", new Blob([fileData], { type: mime }), filename)
  formData.append("model", groqKey ? "whisper-large-v3" : "whisper-1")
  formData.append("response_format", opts.timestamps ? "verbose_json" : "json")
  if (opts.language) formData.append("language", opts.language)
  if (opts.prompt) formData.append("prompt", opts.prompt)

  const providers = [
    ...(groqKey ? [{ name: "groq", url: "https://api.groq.com/openai/v1/audio/transcriptions", key: groqKey }] : []),
    ...(openaiKey ? [{ name: "openai", url: "https://api.openai.com/v1/audio/transcriptions", key: openaiKey }] : []),
  ]

  for (const provider of providers) {
    try {
      const res = await fetch(provider.url, {
        method: "POST",
        headers: { Authorization: `Bearer ${provider.key}` },
        body: formData,
        signal: AbortSignal.timeout(120_000),
      })

      if (!res.ok) {
        const errText = await res.text()
        console.error(`[whisper] ${provider.name} ${res.status}: ${errText.slice(0, 200)}`)
        continue
      }

      const data = await res.json() as any
      return {
        ok: true,
        text: data.text,
        provider: provider.name,
        language: data.language,
        duration: data.duration,
        ...(opts.timestamps && data.segments ? { segments: data.segments } : {}),
      }
    } catch (e) {
      console.error(`[whisper] ${provider.name} failed: ${e}`)
      continue
    }
  }

  return { ok: false, error: "All transcription providers failed." }
}

// ─── CLI ─────────────────────────────────────────────────────────────────────

function parseArgs(argv: string[]): Record<string, string> {
  const flags: Record<string, string> = {}
  const args = argv.slice(2)
  for (let i = 0; i < args.length; i++) {
    const a = args[i]!
    if (a.startsWith("--")) {
      const key = a.slice(2)
      const val = args[i + 1] && !args[i + 1]!.startsWith("--") ? args[++i]! : "true"
      flags[key] = val
    }
  }
  return flags
}

async function main(): Promise<void> {
  const flags = parseArgs(process.argv)

  if (flags.help || (!flags.file && !flags.help)) {
    console.log(`Whisper Transcription CLI\nUsage: bun run transcribe.ts --file <path> [--language <code>] [--timestamps] [--prompt <hint>]`)
    if (!flags.file) process.exit(1)
    return
  }

  const result = await transcribe({
    file: flags.file,
    language: flags.language,
    timestamps: flags.timestamps === "true",
    prompt: flags.prompt,
  })
  console.log(JSON.stringify(result, null, 2))
  process.exit(result.ok ? 0 : 1)
}

if (import.meta.main) {
  main().catch((err) => {
    console.log(JSON.stringify({ ok: false, error: String(err) }))
    process.exit(1)
  })
}

"""
Shared helpers for running LibreOffice headless on Linux and macOS.
"""

import os
import platform
import subprocess
from pathlib import Path

MACRO_DIR = {
    "Darwin": "~/Library/Application Support/LibreOffice/4/user/basic/Standard",
    "Linux": "~/.config/libreoffice/4/user/basic/Standard",
}

TIMEOUT_CMD = {"Darwin": "gtimeout", "Linux": "timeout"}


def soffice_env() -> dict[str, str]:
    env = os.environ.copy()
    env["SAL_USE_VCLPLUGIN"] = "svp"
    return env


def macro_dir() -> Path:
    return Path(os.path.expanduser(MACRO_DIR.get(platform.system(), MACRO_DIR["Linux"])))


def has_timeout_cmd() -> str | None:
    cmd = TIMEOUT_CMD.get(platform.system())
    if not cmd:
        return None
    try:
        subprocess.run([cmd, "--version"], capture_output=True, timeout=1, check=False)
        return cmd
    except (FileNotFoundError, subprocess.TimeoutExpired):
        return None


def run_soffice(args: list[str], timeout: int | None = None) -> subprocess.CompletedProcess[str]:
    cmd = ["soffice", *args]

    if timeout is not None:
        timeout_cmd = has_timeout_cmd()
        if timeout_cmd:
            cmd = [timeout_cmd, str(timeout), *cmd]

    return subprocess.run(cmd, capture_output=True, text=True, env=soffice_env())

"""
Recalculate all formulas in an Excel file via LibreOffice headless, then
scan for residual errors (#REF!, #DIV/0!, etc.).

Usage:
    python recalc.py <excel_file> [timeout_seconds]
"""

import json
import re
import shutil
import subprocess
import sys
import zipfile
from pathlib import Path

from _soffice import macro_dir, run_soffice, soffice_env
from openpyxl import load_workbook

RECALC_MACRO = """\
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE script:module PUBLIC "-//OpenOffice.org//DTD OfficeDocument 1.0//EN" "module.dtd">
<script:module xmlns:script="http://openoffice.org/2000/script" \
script:name="Module1" script:language="StarBasic">
    Sub RecalculateAndSave()
      ThisComponent.calculateAll()
      ThisComponent.store()
      ThisComponent.close(True)
    End Sub
</script:module>"""

MACRO_SCRIPT_URI = "vnd.sun.star.script:Standard.Module1.RecalculateAndSave?language=Basic&location=application"

EXCEL_ERRORS = ("#VALUE!", "#DIV/0!", "#REF!", "#NAME?", "#NULL!", "#NUM!", "#N/A")

TABLE_STYLE_RE = re.compile(rb"<tableStyleInfo[^/>]*/>")

MAX_ERROR_LOCATIONS = 20

DEFAULT_TIMEOUT = 30


def _ensure_macro() -> bool:
    macro_file = macro_dir() / "Module1.xba"

    if macro_file.exists() and "RecalculateAndSave" in macro_file.read_text():
        return True

    if not macro_file.parent.exists():
        subprocess.run(
            ["soffice", "--headless", "--terminate_after_init"],
            capture_output=True,
            timeout=10,
            env=soffice_env(),
        )
        macro_file.parent.mkdir(parents=True, exist_ok=True)

    try:
        macro_file.write_text(RECALC_MACRO)
        return True
    except Exception:
        return False


def _snapshot_table_styles(path: str) -> dict[str, bytes]:
    styles: dict[str, bytes] = {}
    with zipfile.ZipFile(path, "r") as zf:
        for name in zf.namelist():
            if name.startswith("xl/tables/") and name.endswith(".xml"):
                m = TABLE_STYLE_RE.search(zf.read(name))
                if m:
                    styles[name] = m.group(0)
    return styles


def _patch_table_style(data: bytes, style_element: bytes) -> bytes:
    if TABLE_STYLE_RE.search(data):
        return TABLE_STYLE_RE.sub(style_element, data)
    return data.replace(b"</table>", style_element + b"</table>")


def _restore_table_styles(path: str, styles: dict[str, bytes]) -> None:
    if not styles:
        return

    tmp = path + ".tmp"
    try:
        with zipfile.ZipFile(path, "r") as zin, zipfile.ZipFile(tmp, "w") as zout:
            for item in zin.infolist():
                data = zin.read(item.filename)
                if item.filename in styles:
                    data = _patch_table_style(data, styles[item.filename])
                zout.writestr(item, data)
        shutil.move(tmp, path)
    except Exception:
        import os

        if os.path.exists(tmp):
            os.remove(tmp)


def _scan_errors(path: str) -> dict[str, list[str]]:
    wb = load_workbook(path, data_only=True)
    found: dict[str, list[str]] = {e: [] for e in EXCEL_ERRORS}
    for sheet_name in wb.sheetnames:
        for row in wb[sheet_name].iter_rows():
            for cell in row:
                if isinstance(cell.value, str):
                    for err in EXCEL_ERRORS:
                        if err in cell.value:
                            found[err].append(f"{sheet_name}!{cell.coordinate}")
                            break
    wb.close()
    return found


def _count_formulas(path: str) -> int:
    wb = load_workbook(path, data_only=False)
    count = 0
    for sheet_name in wb.sheetnames:
        for row in wb[sheet_name].iter_rows():
            for cell in row:
                if isinstance(cell.value, str) and cell.value.startswith("="):
                    count += 1
    wb.close()
    return count


def recalc(filename: str, timeout: int = DEFAULT_TIMEOUT) -> dict:
    path = Path(filename)
    if not path.exists():
        return {"error": f"File {filename} does not exist"}

    abs_path = str(path.absolute())

    if not _ensure_macro():
        return {"error": "Failed to setup LibreOffice macro"}

    try:
        table_styles = _snapshot_table_styles(abs_path)
    except Exception:
        table_styles = {}

    result = run_soffice(["--headless", "--norestore", MACRO_SCRIPT_URI, abs_path], timeout=timeout)

    if result.returncode not in (0, 124):
        error_msg = result.stderr or "Unknown error during recalculation"
        if "Module1" in error_msg or "RecalculateAndSave" not in error_msg:
            return {"error": "LibreOffice macro not configured properly"}
        return {"error": error_msg}

    try:
        _restore_table_styles(abs_path, table_styles)
    except Exception:
        pass

    try:
        errors = _scan_errors(abs_path)
        total_errors = sum(len(locs) for locs in errors.values())

        summary = {}
        for err_type, locations in errors.items():
            if locations:
                summary[err_type] = {
                    "count": len(locations),
                    "locations": locations[:MAX_ERROR_LOCATIONS],
                }

        return {
            "status": "success" if total_errors == 0 else "errors_found",
            "total_errors": total_errors,
            "total_formulas": _count_formulas(abs_path),
            "error_summary": summary,
        }
    except Exception as e:
        return {"error": str(e)}


def main() -> None:
    if len(sys.argv) < 2:
        print("Usage: python recalc.py <excel_file> [timeout_seconds]")
        sys.exit(1)

    filename = sys.argv[1]
    timeout = int(sys.argv[2]) if len(sys.argv) > 2 else DEFAULT_TIMEOUT
    print(json.dumps(recalc(filename, timeout), indent=2))


if __name__ == "__main__":
    main()
